```class Solution {
public:
    bool divisorGame(int n) {
        int count = 0;
        while (n > 0) {
            if (n % 2 == 0) {
                n /= 2;
            } else {
                count++;
                n = n / 2;
            }
        }
        return count == 0;
    }
};
```

